import React from 'react';

const NextStep = ({ step }) => {
  if (!step) return null;

  return (
    <div className={`p-4 rounded-md ${step.isRecommended ? 'bg-blue-50 border-blue-200 border' : 'bg-gray-50'}`}>
        <h4 className="font-bold text-md">{step.title}</h4>
        <p className="text-sm text-gray-700 mt-1">{step.description}</p>
        {step.isRecommended && (
            <button className="bg-blue-500 text-white font-bold py-2 px-4 rounded mt-3 hover:bg-blue-600"> 
                Accept and Continue
            </button>
        )}
    </div>
  );
};

export default NextStep;
